class Solution(object):
    def doubleIt(self, head):
        def dfs(node):
            if not node:
                return 0
            carry = dfs(node.next)
            val = node.val * 2 + carry
            node.val = val % 10
            return val // 10
        carry = dfs(head)
        if carry:
            new_head = ListNode(carry)
            new_head.next = head
            return new_head
        return head
